class Solution:
    def minSteps(self, s, t):
        from collections import Counter
        cs = Counter(s)
        ct = Counter(t)
        total = 0
        for ch in cs:
            need = cs[ch] - ct.get(ch, 0)
            if need > 0:
                total += need
        return total

